/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * DECISION CHANGE (multi-channel support):
 * This model was originally designed for email-only notifications (Session 3).
 * With the addition of SMS (Session 8) and webhook channels, the email-only
 * assumption is no longer valid. The model now supports per-channel settings
 * for email, SMS, and webhook. Existing email-only preferences remain
 * backward-compatible — the new sms and webhook fields are optional and
 * default to disabled when not present.
 */

import type { NotificationType } from './notification.js';

/**
 * Email frequency settings — controls how often digest emails are sent.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly' | 'none';

/**
 * Email notification preferences for a user.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * SMS notification preferences for a user.
 * SMS does not support frequency batching — messages are always immediate.
 */
export interface SmsPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Webhook notification preferences for a user.
 * Webhooks are always delivered immediately when enabled.
 */
export interface WebhookPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 *
 * The `sms` and `webhook` fields are optional for backward compatibility —
 * preferences created before multi-channel support will only have `email`.
 * When absent, the channel is treated as disabled.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * All available notification categories.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order:confirmation',
  'order:status-update',
  'user:welcome',
  'user:profile-update',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default SMS preferences for new users — disabled by default.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default webhook preferences for new users — disabled by default.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Pure validation functions for notification preferences.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';

/**
 * Determine whether an email notification of the given type should be
 * sent based on the user's preferences.
 *
 * Returns true if:
 *  - No preferences exist (default: send all)
 *  - Email is enabled AND the category is subscribed AND frequency is not 'none'
 *
 * Retained for backward compatibility — delegates to the channel-aware check.
 */
export function shouldSendNotification(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  return shouldSendForChannel(preferences, 'email', notificationType);
}

/**
 * Determine whether a notification should be sent on the given channel
 * based on the user's per-channel preferences.
 *
 * Returns true if:
 *  - No preferences exist (default: send for email only, not for sms/webhook)
 *  - The channel preferences exist, are enabled, and the category is subscribed
 *  - For email: frequency must also not be 'none'
 */
export function shouldSendForChannel(
  preferences: UserPreferences | undefined,
  channel: NotificationChannel,
  notificationType: NotificationType,
): boolean {
  // No preferences stored — default to sending email only (backward compat)
  if (!preferences) {
    return channel === 'email';
  }

  switch (channel) {
    case 'email': {
      const email = preferences.email;
      if (!email.enabled) return false;
      if (email.frequency === 'none') return false;
      return email.subscribedCategories.includes(notificationType);
    }

    case 'sms': {
      const sms = preferences.sms;
      if (!sms || !sms.enabled) return false;
      return sms.subscribedCategories.includes(notificationType);
    }

    case 'webhook': {
      const webhook = preferences.webhook;
      if (!webhook || !webhook.enabled) return false;
      return webhook.subscribedCategories.includes(notificationType);
    }

    default:
      return false;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and methods to check
 * whether a notification should be sent on a given channel based on
 * the user's current settings.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { shouldSendNotification, shouldSendForChannel } from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Create preferences for a user. If no settings are provided for a channel,
   * defaults are used. Email defaults to enabled; SMS and webhook default to
   * disabled (backward compatible).
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const emailPrefs = {
      ...DEFAULT_EMAIL_PREFERENCES,
      ...input.email,
      subscribedCategories: input.email?.subscribedCategories
        ? [...input.email.subscribedCategories]
        : [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
    };

    const smsPrefs = input.sms
      ? {
          ...DEFAULT_SMS_PREFERENCES,
          ...input.sms,
          subscribedCategories: input.sms.subscribedCategories
            ? [...input.sms.subscribedCategories]
            : [...DEFAULT_SMS_PREFERENCES.subscribedCategories],
        }
      : undefined;

    const webhookPrefs = input.webhook
      ? {
          ...DEFAULT_WEBHOOK_PREFERENCES,
          ...input.webhook,
          subscribedCategories: input.webhook.subscribedCategories
            ? [...input.webhook.subscribedCategories]
            : [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories],
        }
      : undefined;

    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: emailPrefs,
      ...(smsPrefs && { sms: smsPrefs }),
      ...(webhookPrefs && { webhook: webhookPrefs }),
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Created preferences for user: ${input.userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  /**
   * Update a user's preferences. Supports partial updates per channel.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? {
          ...existing.email,
          ...input.email,
          subscribedCategories: input.email.subscribedCategories
            ? [...input.email.subscribedCategories]
            : existing.email.subscribedCategories,
        }
      : existing.email;

    const updatedSms = input.sms
      ? {
          ...(existing.sms ?? DEFAULT_SMS_PREFERENCES),
          ...input.sms,
          subscribedCategories: input.sms.subscribedCategories
            ? [...input.sms.subscribedCategories]
            : (existing.sms ?? DEFAULT_SMS_PREFERENCES).subscribedCategories,
        }
      : existing.sms;

    const updatedWebhook = input.webhook
      ? {
          ...(existing.webhook ?? DEFAULT_WEBHOOK_PREFERENCES),
          ...input.webhook,
          subscribedCategories: input.webhook.subscribedCategories
            ? [...input.webhook.subscribedCategories]
            : (existing.webhook ?? DEFAULT_WEBHOOK_PREFERENCES).subscribedCategories,
        }
      : existing.webhook;

    const updated = this.preferencesRepository.update(existing.id, {
      email: updatedEmail,
      ...(updatedSms && { sms: updatedSms }),
      ...(updatedWebhook && { webhook: updatedWebhook }),
      updatedAt: new Date(),
    });

    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Delete a user's preferences.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return this.preferencesRepository.delete(existing.id);
  }

  /**
   * Check whether an email notification of the given type should be
   * sent to the specified user.
   *
   * Retained for backward compatibility. Delegates to shouldSendForChannel.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);
    return shouldSendNotification(prefs, notificationType);
  }

  /**
   * Check whether a notification on the given channel should be sent
   * to the specified user for the given notification type.
   */
  shouldSendForChannel(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);
    return shouldSendForChannel(prefs, channel, notificationType);
  }
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Handles serialization of per-channel preferences (email, sms, webhook).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const emailRaw = JSON.parse(record['email'] as string) as {
      enabled: boolean;
      frequency: string;
      subscribedCategories: string[];
    };

    const result: UserPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: emailRaw.enabled,
        frequency: emailRaw.frequency as EmailPreferences['frequency'],
        subscribedCategories: emailRaw.subscribedCategories as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };

    // Deserialize optional SMS preferences (backward compatible)
    if (record['sms']) {
      const smsRaw = JSON.parse(record['sms'] as string) as {
        enabled: boolean;
        subscribedCategories: string[];
      };
      result.sms = {
        enabled: smsRaw.enabled,
        subscribedCategories: smsRaw.subscribedCategories as NotificationType[],
      };
    }

    // Deserialize optional webhook preferences (backward compatible)
    if (record['webhook']) {
      const webhookRaw = JSON.parse(record['webhook'] as string) as {
        enabled: boolean;
        subscribedCategories: string[];
      };
      result.webhook = {
        enabled: webhookRaw.enabled,
        subscribedCategories: webhookRaw.subscribedCategories as NotificationType[],
      };
    }

    return result;
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };

    if (entity.sms) {
      record['sms'] = JSON.stringify(entity.sms);
    }

    if (entity.webhook) {
      record['webhook'] = JSON.stringify(entity.webhook);
    }

    return record;
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Notification service — orchestrates notification delivery in response
 * to domain events received via EventBus.
 *
 * ARCHITECTURAL DECISION: Event-Driven Pattern
 * ─────────────────────────────────────────────
 * This service subscribes to domain events through the EventBus and
 * dispatches notifications through registered NotificationAdapter instances.
 * It never receives notifications via direct calls or callback registries.
 *
 * Pattern:  EventBus → NotificationService → NotificationAdapter(s)
 *
 * Constraints:
 *  1. ALL notification triggers must flow through EventBus.emit().
 *     Services must not call NotificationService directly.
 *  2. ALL delivery channels must implement the NotificationAdapter interface.
 *     The service dispatches to adapters by channel — it never sends directly.
 *  3. Event handlers are registered in the constructor. To respond to a new
 *     event type, add a handler here and the corresponding event to event-types.ts.
 *  4. Events must carry all data needed by the handler (no additional lookups).
 *
 * MULTI-CHANNEL DISPATCH:
 * Event handlers now iterate over all registered adapter channels and check
 * per-channel preferences before dispatching. This replaced the email-only
 * preference check that was in place before SMS and webhook support.
 *
 * Adding a new notification channel:
 *  1. Create an adapter implementing NotificationAdapter (see src/adapters/).
 *  2. Register it via notificationService.registerAdapter(adapter).
 *  3. The service will automatically check per-channel preferences and
 *     dispatch to the new channel.
 *
 * Adding a new notification trigger:
 *  1. Define the event in src/events/event-types.ts.
 *  2. Emit it from the originating service via EventBus.emit().
 *  3. Add a handler in this service's registerEventHandlers().
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import type { NotificationHistoryService } from './notification-history.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;
  private historyService: NotificationHistoryService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set a preferences service to check user preferences before sending.
   * When no preferences service is set, all notifications are sent (backwards-compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
    this.logger.info('Preferences service registered');
  }

  /**
   * Set a history service to log all sent notifications.
   * When set, every notification (and its delivery result) is recorded.
   */
  setHistoryService(historyService: NotificationHistoryService): void {
    this.historyService = historyService;
    this.logger.info('History service registered');
  }

  /**
   * Register a notification adapter for a given channel.
   * Only one adapter per channel is supported — registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * All event subscriptions are centralized here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendToAllChannels({
      userId: event.user.id,
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      type: 'order:confirmation',
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.sendToAllChannels({
      userId: event.order.userId,
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      type: 'order:status-update',
    });
  }

  /**
   * Send a notification to all channels that the user's preferences allow.
   * For each registered adapter, checks per-channel preferences before dispatching.
   */
  private sendToAllChannels(params: {
    userId: string;
    recipient: string;
    subject: string;
    body: string;
    type: NotificationType;
    metadata?: Record<string, unknown>;
  }): void {
    const channels = Array.from(this.adapters.keys());

    // If no adapters are registered, still send to email channel (backward compat)
    if (channels.length === 0) {
      channels.push('email');
    }

    for (const channel of channels) {
      if (this.preferencesService && !this.preferencesService.shouldSendForChannel(params.userId, channel, params.type)) {
        this.logger.info(`Skipping ${channel} ${params.type} for user ${params.userId} — user preferences`);
        continue;
      }

      // When no preferences service is set and channel is not email, skip
      // (backward compat: only email is sent by default)
      if (!this.preferencesService && channel !== 'email') {
        continue;
      }

      this.logger.info(`Sending ${params.type} via ${channel} for user ${params.userId}`);

      this.sendNotification({
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        type: params.type,
        channel,
        metadata: params.metadata,
      });
    }
  }

  /**
   * Send a notification: record it and dispatch to the appropriate adapter.
   */
  private sendNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      sentAt: new Date(),
      metadata: payload.metadata,
    };

    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);

    // Dispatch to adapter if one is registered for this channel
    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      adapter.send({ ...payload }).then((result: NotificationResult) => {
        if (!result.success) {
          this.logger.error(
            `Adapter delivery failed for ${notification.id}: ${result.error}`,
          );
        }
        // Log with delivery result
        if (this.historyService) {
          this.historyService.record(notification, result);
        }
      });
    } else if (this.historyService) {
      // No adapter — log as sent (no delivery confirmation possible)
      this.historyService.record(notification);
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

import { describe, it, expect } from 'vitest';
import { shouldSendNotification, shouldSendForChannel } from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

const makePrefs = (
  overrides: Partial<UserPreferences['email']> = {},
  sms?: UserPreferences['sms'],
  webhook?: UserPreferences['webhook'],
): UserPreferences => ({
  id: 'pref-0001',
  userId: 'user-0001',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: ['order:confirmation', 'order:status-update'],
    ...overrides,
  },
  ...(sms && { sms }),
  ...(webhook && { webhook }),
  createdAt: new Date(),
  updatedAt: new Date(),
});

describe('preferences validators', () => {
  describe('shouldSendNotification (backward compat)', () => {
    it('should return true when no preferences exist', () => {
      expect(shouldSendNotification(undefined, 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      expect(
        shouldSendNotification(makePrefs(), 'order:confirmation'),
      ).toBe(true);
    });

    it('should return false when email is disabled', () => {
      expect(
        shouldSendNotification(makePrefs({ enabled: false }), 'order:confirmation'),
      ).toBe(false);
    });

    it('should return false when frequency is none', () => {
      expect(
        shouldSendNotification(makePrefs({ frequency: 'none' }), 'order:confirmation'),
      ).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      expect(
        shouldSendNotification(makePrefs(), 'user:welcome'),
      ).toBe(false);
    });

    it('should return true for subscribed category with daily frequency', () => {
      expect(
        shouldSendNotification(
          makePrefs({ frequency: 'daily' }),
          'order:confirmation',
        ),
      ).toBe(true);
    });
  });

  describe('shouldSendForChannel', () => {
    describe('email channel', () => {
      it('should return true when no preferences exist', () => {
        expect(shouldSendForChannel(undefined, 'email', 'order:confirmation')).toBe(true);
      });

      it('should return true when email is enabled and category subscribed', () => {
        expect(shouldSendForChannel(makePrefs(), 'email', 'order:confirmation')).toBe(true);
      });

      it('should return false when email is disabled', () => {
        expect(shouldSendForChannel(makePrefs({ enabled: false }), 'email', 'order:confirmation')).toBe(false);
      });

      it('should return false when frequency is none', () => {
        expect(shouldSendForChannel(makePrefs({ frequency: 'none' }), 'email', 'order:confirmation')).toBe(false);
      });
    });

    describe('sms channel', () => {
      it('should return false when no preferences exist', () => {
        expect(shouldSendForChannel(undefined, 'sms', 'order:confirmation')).toBe(false);
      });

      it('should return false when sms preferences are absent', () => {
        expect(shouldSendForChannel(makePrefs(), 'sms', 'order:confirmation')).toBe(false);
      });

      it('should return false when sms is disabled', () => {
        const prefs = makePrefs({}, { enabled: false, subscribedCategories: ['order:confirmation'] });
        expect(shouldSendForChannel(prefs, 'sms', 'order:confirmation')).toBe(false);
      });

      it('should return true when sms is enabled and category subscribed', () => {
        const prefs = makePrefs({}, { enabled: true, subscribedCategories: ['order:confirmation'] });
        expect(shouldSendForChannel(prefs, 'sms', 'order:confirmation')).toBe(true);
      });

      it('should return false when category is not subscribed for sms', () => {
        const prefs = makePrefs({}, { enabled: true, subscribedCategories: ['order:confirmation'] });
        expect(shouldSendForChannel(prefs, 'sms', 'user:welcome')).toBe(false);
      });
    });

    describe('webhook channel', () => {
      it('should return false when no preferences exist', () => {
        expect(shouldSendForChannel(undefined, 'webhook', 'order:confirmation')).toBe(false);
      });

      it('should return false when webhook preferences are absent', () => {
        expect(shouldSendForChannel(makePrefs(), 'webhook', 'order:confirmation')).toBe(false);
      });

      it('should return true when webhook is enabled and category subscribed', () => {
        const prefs = makePrefs(
          {},
          undefined,
          { enabled: true, subscribedCategories: ['order:confirmation', 'order:status-update'] },
        );
        expect(shouldSendForChannel(prefs, 'webhook', 'order:confirmation')).toBe(true);
      });

      it('should return false when webhook is disabled', () => {
        const prefs = makePrefs(
          {},
          undefined,
          { enabled: false, subscribedCategories: ['order:confirmation'] },
        );
        expect(shouldSendForChannel(prefs, 'webhook', 'order:confirmation')).toBe(false);
      });
    });

    describe('unknown channel', () => {
      it('should return false for in-app channel (no preferences support)', () => {
        expect(shouldSendForChannel(makePrefs(), 'in-app', 'order:confirmation')).toBe(false);
      });
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toContain('order:confirmation');
      expect(prefs.email.subscribedCategories).toContain('order:status-update');
      expect(prefs.email.subscribedCategories).toContain('user:welcome');
      expect(prefs.email.subscribedCategories).toContain('user:profile-update');
      // SMS and webhook should not be set by default
      expect(prefs.sms).toBeUndefined();
      expect(prefs.webhook).toBeUndefined();
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily',
          subscribedCategories: ['order:confirmation'],
        },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should create preferences with SMS enabled', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: {
          enabled: true,
          subscribedCategories: ['order:confirmation'],
        },
      });

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should create preferences with webhook enabled', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        webhook: {
          enabled: true,
          subscribedCategories: ['order:status-update'],
        },
      });

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.subscribedCategories).toEqual(['order:status-update']);
    });

    it('should create preferences with all channels', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily' },
        sms: { enabled: true },
        webhook: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.sms!.enabled).toBe(true);
      // SMS should default all categories when not specified
      expect(prefs.sms!.subscribedCategories).toContain('order:confirmation');
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for existing user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('user-999')).toBeUndefined();
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should return existing preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly' },
      });

      const prefs = service.getOrCreatePreferences('user-1');
      expect(prefs.email.frequency).toBe('weekly');
    });

    it('should create default preferences if none exist', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
    });
  });

  describe('updatePreferences', () => {
    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order:confirmation'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should disable email notifications', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
    });

    it('should add SMS preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      expect(updated.sms).toBeDefined();
      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should add webhook preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: true },
      });

      expect(updated.webhook).toBeDefined();
      expect(updated.webhook!.enabled).toBe(true);
    });

    it('should update SMS preferences without affecting email', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      const updated = service.updatePreferences('user-1', {
        sms: { subscribedCategories: ['order:confirmation', 'order:status-update'] },
      });

      expect(updated.email.enabled).toBe(true); // unchanged
      expect(updated.sms!.subscribedCategories).toEqual(['order:confirmation', 'order:status-update']);
    });

    it('should throw if preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('user-999', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-999');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false for non-existent preferences', () => {
      expect(service.deletePreferences('user-999')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({ userId: 'user-1' });
      service.updatePreferences('user-1', { email: { enabled: false } });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.createPreferences({ userId: 'user-1' });
      service.updatePreferences('user-1', { email: { frequency: 'none' } });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation'] },
      });

      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(false);
    });

    it('should return true for subscribed category with daily frequency', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily', subscribedCategories: ['order:confirmation'] },
      });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });
  });

  describe('shouldSendForChannel', () => {
    it('should check SMS preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      expect(service.shouldSendForChannel('user-1', 'sms', 'order:confirmation')).toBe(true);
      expect(service.shouldSendForChannel('user-1', 'sms', 'user:welcome')).toBe(false);
    });

    it('should return false for SMS when no SMS preferences exist', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendForChannel('user-1', 'sms', 'order:confirmation')).toBe(false);
    });

    it('should check webhook preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true, subscribedCategories: ['order:status-update'] },
      });

      expect(service.shouldSendForChannel('user-1', 'webhook', 'order:status-update')).toBe(true);
      expect(service.shouldSendForChannel('user-1', 'webhook', 'order:confirmation')).toBe(false);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setPreferencesService(service);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      resetNotificationIdCounter();
    });

    it('should send notification when user has no preferences (default)', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should skip notification when user has disabled email', async () => {
      service.createPreferences({ userId: 'user-1' });
      service.updatePreferences('user-1', { email: { enabled: false } });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should skip notification when category is unsubscribed', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['user:welcome'] },
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should respect preferences for order status change events', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation'] },
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send notification when preferences allow the category', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation', 'order:status-update'] },
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should send to multiple channels when preferences allow', async () => {
      const smsAdapter = new SmsAdapter();
      notificationService.registerAdapter(smsAdapter);

      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation'] },
        sms: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      // Should send to both email and SMS
      expect(notificationService.getNotificationCount()).toBe(2);
      const notifications = notificationService.getNotifications();
      const channels = notifications.map((n) => n.channel);
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
    });

    it('should send email but not SMS when SMS is not enabled', async () => {
      const smsAdapter = new SmsAdapter();
      notificationService.registerAdapter(smsAdapter);

      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation'] },
        // No SMS preferences — defaults to disabled
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('email');
    });

    it('should send to all three channels when all are enabled', async () => {
      const smsAdapter = new SmsAdapter();
      const webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
      notificationService.registerAdapter(smsAdapter);
      notificationService.registerAdapter(webhookAdapter);

      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order:confirmation'] },
        sms: { enabled: true, subscribedCategories: ['order:confirmation'] },
        webhook: { enabled: true, subscribedCategories: ['order:confirmation'] },
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(3);
      const channels = notificationService.getNotifications().map((n) => n.channel);
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
    });
  });
});

